pub fn lookup(query: &str) -> Option<&'static SpaceGroupData> {
    let q = query.trim().replace(' ', "").to_lowercase();
    let q_nodash = q.replace('-', "");
    if let Some(rest) = q.strip_prefix('#') {
        if let Ok(n) = rest.parse::<u16>() {
            return SPACE_GROUPS.iter().find(|sg| sg.number == n);
        }
    }
    SPACE_GROUPS.iter().find(|sg| {
        sg.canonical_name.replace(' ', "").replace('-', "").to_lowercase() == q_nodash
    })
}
